// /frontend/src/components/Forecast.jsx
import React from "react";

const fmtTime = (s) => {
  const d = new Date(((s ?? 0) | 0) * 1000);
  return isNaN(d) ? "—" : d.toLocaleTimeString([], { hour: "numeric" });
};
const fmtDay = (s) => {
  const d = new Date(((s ?? 0) | 0) * 1000);
  return isNaN(d) ? "—" : d.toLocaleDateString([], { weekday: "short" });
};
const val = (n) => (Number.isFinite(n) ? Math.round(n) : "—");

export default function Forecast({ hourly = [], daily = [], daily16 = [] }) {
  const hasHourly = Array.isArray(hourly) && hourly.length > 0;
  const hasDaily  = Array.isArray(daily)  && daily.length  > 0;
  const has16     = Array.isArray(daily16) && daily16.length > 0;

  return (
    <div className="grid gap-6">
      {/* Hourly */}
      <section className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
        <div className="font-semibold mb-3">Hourly (next 12)</div>
        {hasHourly ? (
          <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 gap-3">
            {hourly.slice(0, 12).map((h, i) => (
              <div key={i} className="rounded-xl bg-white/10 p-3 text-sm">
                <div className="opacity-80">{fmtTime(h?.date)}</div>
                <div className="text-2xl font-bold">{val(h?.temp)}°</div>
                <div className="opacity-80">{h?.weather || "—"}</div>
                {Number.isFinite(h?.pop) && (
                  <div className="text-xs opacity-70 mt-1">POP {val(h.pop * 100)}%</div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="text-sm opacity-80">No hourly data.</div>
        )}
      </section>

      {/* Daily */}
      <section className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
        <div className="font-semibold mb-3">Daily</div>
        {hasDaily ? (
          <div className="grid gap-2">
            {daily.slice(0, 10).map((d, i) => (
              <div key={i} className="flex items-center justify-between rounded-xl bg-white/10 p-3 text-sm">
                <div className="w-24">{fmtDay(d?.date)}</div>
                <div className="flex-1 opacity-80">{d?.weather || "—"}</div>
                <div className="font-bold">
                  {val(d?.temp?.max)}° / {val(d?.temp?.min)}°
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-sm opacity-80">No daily data.</div>
        )}
      </section>

      {/* Extended (16‑day) */}
      <section className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
        <div className="font-semibold mb-3">Extended (16‑day)</div>
        {has16 ? (
          <div className="grid gap-2">
            {daily16.map((d, i) => (
              <div key={i} className="flex items-center justify-between rounded-xl bg-white/10 p-3 text-sm">
                <div className="w-24">{fmtDay(d?.date)}</div>
                <div className="flex-1 opacity-80">{d?.weather || "—"}</div>
                <div className="font-bold">
                  {val(d?.temp?.max)}° / {val(d?.temp?.min)}°
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-sm opacity-80">No extended forecast available.</div>
        )}
      </section>
    </div>
  );
}
